export class ThemeManager{constructor(){this.theme=localStorage.getItem("theme")||"light",this.init()}init(){this.applyTheme(),this.bindEvents()}applyTheme(){document.documentElement.setAttribute("data-theme",this.theme),this.updateIcon()}updateIcon(){const e=document.querySelector("#themeToggle .theme-icon, #theme-toggle .material-symbols-outlined");e&&(e.textContent="dark"===this.theme?"🌞":"🌙")}toggle(){this.theme="light"===this.theme?"dark":"light",localStorage.setItem("theme",this.theme),this.applyTheme()}bindEvents(){const e=document.getElementById("themeToggle")||document.getElementById("theme-toggle");e&&e.addEventListener("click",()=>this.toggle())}}new ThemeManager;